sys_script_include.script:
var MetadataMappingUtils = Class.create();

MetadataMappingUtils.prototype = {

    initialize: function() {
    },

    getFieldTypeQualifier: function(current) {

        var dataModel = current.data_model_object_id;

        if (!dataModel)
            return '';

        var dataModelGR = new GlideRecordSecure('x_ctans_incentnow_data_model_object');

        if (dataModelGR.get(dataModel)) {

            if (dataModelGR.data_source_system == 'External') {

                return "nameINinteger,decimal,string,glide_date_time,currency";

            }

        }

        return '';

    },

    type: 'MetadataMappingUtils'
};
